const output = [];

for (const item of items) {

  const data = item.json;

  // Pick first available mobile
  const mobile =
    data.Account_Mobile_Number__c ||
    data.Account_Mobile_1__c ||
    data.Mobile_Number__c ||
    data.PrimaryMobileNumber__c ||
    null;

  // Skip if no mobile
  if (!mobile) continue;

  // Status validation
  if (data.Status__c !== "Processed") {
    continue;
  }

  // Parse agreement value (handles values like 6,00,00,000)
  const agreementValue = Number(
    String(data.Agreement_Value__c || "0")
      .replace(/,/g, "")
      .trim()
  );

  if (isNaN(agreementValue)) {
    continue;
  }

  // Parse dates
  const bookingDate = new Date(data.Booking_Date);
  const svDate = new Date(data.SV_Date__c);

  // Invalid dates
  if (
    isNaN(bookingDate.getTime()) ||
    isNaN(svDate.getTime())
  ) {
    continue;
  }

  // Remove time component to avoid timezone issues
  bookingDate.setHours(0, 0, 0, 0);
  svDate.setHours(0, 0, 0, 0);

  // Difference in days
  const diffDays = Math.floor(
    (bookingDate - svDate) / 86400000
  );

  let amount = 0;
  let ruleApplied = "";

  // Rule 1: Agreement Value >= 5 Cr and booking within 30 days
  if (
    agreementValue >= 50000000 &&
    diffDays >= 0 &&
    diffDays <= 30
  ) {
    amount = 500;
    ruleApplied = ">=5Cr within 30 days";
  }

  // Rule 2: Agreement Value < 5 Cr and booking within 15 days
  else if (
    agreementValue < 50000000 &&
    diffDays >= 0 &&
    diffDays <= 15
  ) {
    amount = 1000;
    ruleApplied = "<5Cr within 15 days";
  }

  // Not eligible
  else {
    continue;
  }

  output.push({
    json: {
      id: data.ID,

      customer_code: data.KUNNR,

      customer_mobile: String(mobile),

      customer_name: [
        data.First_Name__c,
        data.Last_Name__c
      ]
        .filter(Boolean)
        .join(" "),

      amount: amount,

      remarks:
        "Booking within eligible Site Visit duration",

      transaction_note:
        "Credit points based on Agreement Value and Booking Date",

      payment_mode: "cash",

      topup_by: "automation",

      booking_date: data.Booking_Date,

      sv_date: data.SV_Date__c,

      booking_id:
        data.X18_Digit_Booking_ID__c,

      agreement_value: agreementValue,

      days_difference: diffDays,

      rule_applied: ruleApplied,

      today_delta_additions:
        data.today_delta_additions
    }
  });
}

return output;
